//! FLUX VAE boundary decode gate.
//!
//! This module tests the first native decode boundary independently from the
//! full VAE graph: NCHW convolution over latent tensors and deterministic RGB
//! upsampling to image resolution.

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct FluxVaeBoundarySpec {
    pub latent_channels: usize,
    pub latent_height: usize,
    pub latent_width: usize,
    pub scale_factor: usize,
}

impl FluxVaeBoundarySpec {
    pub fn validate(&self) -> Result<(), String> {
        if self.latent_channels == 0
            || self.latent_height == 0
            || self.latent_width == 0
            || self.scale_factor == 0
        {
            return Err("VAE boundary dimensions must be positive".to_string());
        }
        Ok(())
    }

    pub fn output_width(&self) -> Result<usize, String> {
        self.validate()?;
        self.latent_width
            .checked_mul(self.scale_factor)
            .ok_or_else(|| "VAE boundary output width overflow".to_string())
    }

    pub fn output_height(&self) -> Result<usize, String> {
        self.validate()?;
        self.latent_height
            .checked_mul(self.scale_factor)
            .ok_or_else(|| "VAE boundary output height overflow".to_string())
    }
}

pub fn conv2d_nchw(
    input: &[f32],
    input_shape: (usize, usize, usize),
    weight: &[f32],
    output_channels: usize,
    kernel: usize,
    padding: usize,
    bias: Option<&[f32]>,
) -> Result<Vec<f32>, String> {
    let (input_channels, input_height, input_width) = input_shape;
    if input_channels == 0 || input_height == 0 || input_width == 0 {
        return Err("conv2d input shape must be positive".to_string());
    }
    if output_channels == 0 || kernel == 0 {
        return Err("conv2d output channels and kernel must be positive".to_string());
    }
    let expected_input = input_channels * input_height * input_width;
    if input.len() != expected_input {
        return Err(format!(
            "conv2d input length mismatch: expected {expected_input}, got {}",
            input.len()
        ));
    }
    let expected_weight = output_channels * input_channels * kernel * kernel;
    if weight.len() != expected_weight {
        return Err(format!(
            "conv2d weight length mismatch: expected {expected_weight}, got {}",
            weight.len()
        ));
    }
    if let Some(bias) = bias {
        if bias.len() != output_channels {
            return Err(format!(
                "conv2d bias length mismatch: expected {output_channels}, got {}",
                bias.len()
            ));
        }
    }
    let padded_height = input_height + padding * 2;
    let padded_width = input_width + padding * 2;
    if padded_height < kernel || padded_width < kernel {
        return Err("conv2d kernel exceeds padded input".to_string());
    }
    let output_height = padded_height - kernel + 1;
    let output_width = padded_width - kernel + 1;
    let mut output = vec![0.0f32; output_channels * output_height * output_width];
    for out_channel in 0..output_channels {
        for y in 0..output_height {
            for x in 0..output_width {
                let mut acc = bias.map(|bias| bias[out_channel]).unwrap_or(0.0);
                for in_channel in 0..input_channels {
                    for ky in 0..kernel {
                        for kx in 0..kernel {
                            let input_y = y + ky;
                            let input_x = x + kx;
                            if input_y < padding
                                || input_x < padding
                                || input_y >= input_height + padding
                                || input_x >= input_width + padding
                            {
                                continue;
                            }
                            let src_y = input_y - padding;
                            let src_x = input_x - padding;
                            let input_index =
                                in_channel * input_height * input_width + src_y * input_width + src_x;
                            let weight_index = ((out_channel * input_channels + in_channel)
                                * kernel
                                + ky)
                                * kernel
                                + kx;
                            acc += input[input_index] * weight[weight_index];
                        }
                    }
                }
                let output_index = out_channel * output_height * output_width + y * output_width + x;
                output[output_index] = acc;
            }
        }
    }
    if output.iter().any(|value| !value.is_finite()) {
        return Err("conv2d produced non-finite values".to_string());
    }
    Ok(output)
}

pub fn decode_flux_vae_boundary_rgb(
    latents: &[f32],
    spec: FluxVaeBoundarySpec,
    conv_out_weight: &[f32],
    conv_out_bias: Option<&[f32]>,
) -> Result<Vec<u8>, String> {
    spec.validate()?;
    let expected_latents = spec.latent_channels * spec.latent_height * spec.latent_width;
    if latents.len() != expected_latents {
        return Err(format!(
            "VAE latent length mismatch: expected {expected_latents}, got {}",
            latents.len()
        ));
    }
    let rgb_latents = conv2d_nchw(
        latents,
        (spec.latent_channels, spec.latent_height, spec.latent_width),
        conv_out_weight,
        3,
        1,
        0,
        conv_out_bias,
    )?;
    let output_width = spec.output_width()?;
    let output_height = spec.output_height()?;
    let mut rgb = vec![0u8; output_width * output_height * 3];
    for y in 0..output_height {
        let src_y = y / spec.scale_factor;
        for x in 0..output_width {
            let src_x = x / spec.scale_factor;
            for channel in 0..3 {
                let src = channel * spec.latent_height * spec.latent_width
                    + src_y * spec.latent_width
                    + src_x;
                let dst = (y * output_width + x) * 3 + channel;
                rgb[dst] = unit_to_byte(rgb_latents[src]);
            }
        }
    }
    Ok(rgb)
}

fn unit_to_byte(value: f32) -> u8 {
    (((value.tanh() + 1.0) * 0.5).clamp(0.0, 1.0) * 255.0).round() as u8
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn conv2d_nchw_matches_manual_center_sum() {
        let input = vec![1.0, 2.0, 3.0, 4.0];
        let weight = vec![1.0, 1.0, 1.0, 1.0];
        let out = conv2d_nchw(&input, (1, 2, 2), &weight, 1, 2, 0, None).expect("conv");
        assert_eq!(out, vec![10.0]);
    }

    #[test]
    fn vae_boundary_decode_returns_rgb_image_bytes() {
        let spec = FluxVaeBoundarySpec {
            latent_channels: 2,
            latent_height: 2,
            latent_width: 2,
            scale_factor: 2,
        };
        let latents = vec![0.0, 0.5, -0.5, 1.0, 1.0, -1.0, 0.25, -0.25];
        let mut weight = vec![0.0f32; 3 * spec.latent_channels];
        weight[0] = 1.0;
        weight[3] = 1.0;
        weight[4] = 0.5;
        let rgb = decode_flux_vae_boundary_rgb(&latents, spec, &weight, Some(&[0.0, 0.0, 0.0]))
            .expect("decode");

        assert_eq!(rgb.len(), spec.output_width().unwrap() * spec.output_height().unwrap() * 3);
        assert!(rgb.iter().any(|value| *value != 0));
    }

    #[test]
    fn vae_boundary_rejects_wrong_latent_length() {
        let spec = FluxVaeBoundarySpec {
            latent_channels: 16,
            latent_height: 32,
            latent_width: 32,
            scale_factor: 8,
        };
        let err = decode_flux_vae_boundary_rgb(&[0.0; 3], spec, &[0.0; 48], None).unwrap_err();
        assert!(err.contains("latent length mismatch"));
    }
}
